import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSSafeServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = sanitizeInput(userInput);

        String output = "<div>" + sanitizedInput + "</div>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeInput(String input) {
        // Implement your own input sanitization logic here
        // For a simple example, you can use OWASP Java HTML Sanitizer library
        return org.owasp.html.Sanitizers.BLOCKS_ALWAYS_ALLOWED.sanitize(input);
    }
}

